package policy

import (
	"context"
	"encoding/json"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
	"github.com/cilium/cilium/pkg/policy/api"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	mu       lock.Mutex
	logLevel logrus.Level
	logger   logrus.FieldLogger
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the given log level
// and logger instance.
func NewPolicyAuditLogger(logger logrus.FieldLogger, level logrus.Level) *PolicyAuditLogger {
	if logger == nil {
		logger = log
	}
	return &PolicyAuditLogger{
		logLevel: level,
		logger:   logger,
	}
}

// LogDecision logs a policy decision with identity, policy, verdict, and reason.
// This method is thread-safe.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict api.Decision, reason string) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	if !pal.shouldLog() {
		return
	}

	fields := logrus.Fields{
		logfields.Identity:     identity,
		"policyName":           policy,
		"verdict":              verdict.String(),
		"reason":               reason,
	}

	pal.logWithFields(fields, "Policy decision logged")
}

// LogEvaluation logs a policy evaluation result with context, policy key, selector cache,
// and evaluation result. This method is thread-safe.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result interface{}) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	if !pal.shouldLog() {
		return
	}

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
	}

	// Add result information if available
	if result != nil {
		// Convert result to JSON for structured logging
		if jsonBytes, err := json.Marshal(result); err == nil {
			fields["evaluationResult"] = string(jsonBytes)
		} else {
			fields["evaluationResult"] = result
		}
	}

	// Add selector cache info if available
	if selectorCache != nil {
		fields["selectorCacheActive"] = true
	}

	pal.logWithFields(fields, "Policy evaluation logged")
}

// shouldLog checks if the current log level allows logging at the logger's configured level
func (pal *PolicyAuditLogger) shouldLog() bool {
	// Get the current logger's level and compare with our configured level
	if entry, ok := pal.logger.(*logrus.Entry); ok {
		return entry.Logger.IsLevelEnabled(pal.logLevel)
	}
	if logger, ok := pal.logger.(*logrus.Logger); ok {
		return logger.IsLevelEnabled(pal.logLevel)
	}
	// If we can't determine the level, allow logging
	return true
}

// logWithFields logs a message with the given fields at the configured log level
func (pal *PolicyAuditLogger) logWithFields(fields logrus.Fields, message string) {
	entry := pal.logger.WithFields(fields)

	switch pal.logLevel {
	case logrus.DebugLevel:
		entry.Debug(message)
	case logrus.InfoLevel:
		entry.Info(message)
	case logrus.WarnLevel:
		entry.Warn(message)
	case logrus.ErrorLevel:
		entry.Error(message)
	default:
		entry.Debug(message)
	}
}

// SetLogLevel updates the log level for this audit logger
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	pal.logLevel = level
}

// GetLogLevel returns the current log level
func (pal *PolicyAuditLogger) GetLogLevel() logrus.Level {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	return pal.logLevel
}

