// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/policy/api"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := logrus.New()
	fieldLogger := logger.WithField("test", "value")

	// Test with custom logger
	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)
	require.Equal(t, logrus.InfoLevel, auditor.GetLogLevel())

	// Test with nil logger (should use default)
	auditor2 := NewPolicyAuditLogger(nil, logrus.DebugLevel)
	require.NotNil(t, auditor2)
	require.Equal(t, logrus.DebugLevel, auditor2.GetLogLevel())
}

func TestLogDecision(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "audit")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)

	// Test logging allowed decision
	testID := identity.NumericIdentity(1001)
	auditor.LogDecision(testID, "test-policy", api.Allowed, "matched ingress rule")
	// No panic should occur

	// Test logging denied decision
	auditor.LogDecision(testID, "deny-policy", api.Denied, "matched deny rule")
	// No panic should occur

	// Test logging undecided
	auditor.LogDecision(testID, "undecided-policy", api.Undecided, "no matching rules")
	// No panic should occur
}

func TestLogEvaluation(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "audit")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.DebugLevel)
	require.NotNil(t, auditor)

	ctx := context.Background()

	// Test with nil result
	auditor.LogEvaluation(ctx, "policy-key-1", nil, nil)
	// No panic should occur

	// Test with map result
	result := map[string]interface{}{
		"matched":    true,
		"ruleCount":  3,
		"selectores": []string{"app=web"},
	}
	auditor.LogEvaluation(ctx, "policy-key-2", nil, result)
	// No panic should occur

	// Test with string result
	auditor.LogEvaluation(ctx, "policy-key-3", nil, "test result")
	// No panic should occur
}

func TestLogDecisionThreadSafety(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "thread")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)

	// Run concurrent logging
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(id int) {
			testID := identity.NumericIdentity(1000 + id)
			auditor.LogDecision(testID, "thread-test", api.Allowed, "concurrent test")
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		<-done
	}
	// No panic should occur
}

func TestLogEvaluationThreadSafety(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "thread")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.DebugLevel)
	require.NotNil(t, auditor)

	ctx := context.Background()

	// Run concurrent evaluation logging
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(id int) {
			result := map[string]int{"evaluationID": id}
			auditor.LogEvaluation(ctx, "key-"+string(rune(id)), nil, result)
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		<-done
	}
	// No panic should occur
}

func TestSetAndGetLogLevel(t *testing.T) {
	logger := logrus.New()
	fieldLogger := logger.WithField("test", "level")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.Equal(t, logrus.InfoLevel, auditor.GetLogLevel())

	// Change log level
	auditor.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, auditor.GetLogLevel())

	auditor.SetLogLevel(logrus.WarnLevel)
	require.Equal(t, logrus.WarnLevel, auditor.GetLogLevel())

	auditor.SetLogLevel(logrus.ErrorLevel)
	require.Equal(t, logrus.ErrorLevel, auditor.GetLogLevel())
}

func TestLogDecisionWithDifferentVerdicts(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "verdicts")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.InfoLevel)
	require.NotNil(t, auditor)

	testID := identity.NumericIdentity(2001)

	// Test all verdict types
	verdicts := []api.Decision{
		api.Allowed,
		api.Denied,
		api.Undecided,
	}

	for _, verdict := range verdicts {
		auditor.LogDecision(testID, "test-policy", verdict, "testing verdict: "+verdict.String())
		// Verify verdict string representation works
		require.NotEmpty(t, verdict.String())
	}
}

func TestLogEvaluationWithComplexResult(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	fieldLogger := logger.WithField("test", "complex")

	auditor := NewPolicyAuditLogger(fieldLogger, logrus.DebugLevel)
